import java.util.ArrayList;import java.util.List;import java.util.Map;
final class IteratorPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}static final class PageIterator{final List<Object>pages;int pageIndex,itemIndex,fetched;List<Object>items=List.of();PageIterator(List<Object>p){pages=p;}Integer next(){while(itemIndex>=items.size()){if(pageIndex>=pages.size())return null;Object page=pages.get(pageIndex++);if(page instanceof Map<?,?>failure)throw new PatternException(String.valueOf(failure.get("error")));items=(List<Object>)page;itemIndex=0;fetched++;}return((Number)items.get(itemIndex++)).intValue();}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){PageIterator iterator=new PageIterator((List<Object>)input.getOrDefault("pages",List.of()));List<Integer>items=new ArrayList<>();boolean exhausted=false;int take=((Number)input.getOrDefault("take",0)).intValue();for(int i=0;i<take;i++){Integer value=iterator.next();if(value==null){exhausted=true;break;}items.add(value);}return Map.of("items",items,"fetched_pages",iterator.fetched,"exhausted",exhausted);}}
